1	// Edge function: submit-video (US-045)
2	//
3	// Contract:
4	//   POST { application_id: string,
5	//          video_url: string,
6	//          post_condition_affirmations: { [condition_id: string]: boolean } }
7	//     → 200 { submission_id: string, platform: 'tiktok'|'instagram' }
8	//     → 400 { error: 'INVALID_JSON' | 'INVALID_REQUEST' }
9	//     → 401 { error: 'UNAUTHORIZED' }
10	//     → 403 { error: 'FORBIDDEN' }                       // non-creator role
11	//     → 403 { error: 'APPLICATION_NOT_APPROVED' }
12	//     → 404 { error: 'APPLICATION_NOT_FOUND' }
13	//     → 409 { error: 'SUBMISSION_EXISTS' }
14	//     → 422 { error: 'INVALID_VIDEO_URL' }
15	//     → 422 { error: 'INCOMPLETE_AFFIRMATIONS',
16	//             missing_condition_ids: string[] }
17	//     → 500 { error: 'SERVER_MISCONFIGURED' | 'DB_ERROR' }
18	//
19	// Auth: Marketify JWT (HS256, MARKETIFY_JWT_SECRET). Deployed with
20	//       verify_jwt=false at the gateway because the gateway only knows
21	//       about Supabase's own JWT secret — the handler enforces auth.
22	//
23	// Request shape — the US-045 story AC specifies `{ application_id,
24	// video_url, post_condition_affirmations }`. The tech-architecture spec
25	// §5.7 names a future-compatible `{ videos: [...] }` array shape; per
26	// the Ralph convention when story AC and spec disagree at the field
27	// level the story AC wins. The DB layer models multi-video via
28	// `submission_videos.sort_order` so expanding to an array later is a
29	// non-breaking change to this endpoint.
30	//
31	// URL validation (docs/tech-architecture.md §3h):
32	//   - TikTok canonical + shortlinks accepted; canonical gives us the
33	//     numeric `external_id`.
34	//   - TikTok oEmbed endpoint is called to prove the URL points at a
35	//     real, currently-resolvable post. A 404 from TikTok → 422
36	//     INVALID_VIDEO_URL. Network/5xx failures from TikTok → 500.
37	//   - Instagram URLs are validated by regex-shape only because IG
38	//     oEmbed requires an app-level Meta token that we do not currently
39	//     have provisioned. See `_shared/oembed.ts` header.
40	//
41	// Affirmation gate — the spec treats POST conditions (e.g.
42	// "must_mention", "family_friendly") as creator attestations at
43	// submit-time rather than machine-checkable facts. Every `post`-kind
44	// condition on the application's pinned listing_version_id must appear
45	// in `post_condition_affirmations` with a literal `true` value. Missing
46	// or `false` entries → 422 INCOMPLETE_AFFIRMATIONS with the offending
47	// ids so the client can re-surface them.
48	//
49	// Concurrency — the RPC acquires a row lock on the application
50	// (FOR UPDATE) so a duplicate submit interleaving with this one is
51	// serialised and the second request receives SUBMISSION_EXISTS. The
52	// partial unique index `submissions_open_uniq` is the DB backstop.
53	
54	import { createClient } from "npm:@supabase/supabase-js@2";
55	import { verifyJwt } from "../_shared/jwt.ts";
56	import { corsHeaders } from "../_shared/cors.ts";
57	import {
58	  classifyVideoUrl,
59	  fetchTikTokOembed,
60	  type OembedResult,
61	} from "../_shared/oembed.ts";
62	
63	const UUID_RE =
64	  /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
65	
66	// Guard against a malicious client pasting a megabyte of URL. TikTok /
67	// Instagram share URLs cap well under 300 chars in the wild; 2048 is
68	// the de facto browser URL ceiling.
69	const VIDEO_URL_MAX_LEN = 2048;
70	
71	interface SubmitVideoRequest {
72	  application_id?: unknown;
73	  video_url?: unknown;
74	  post_condition_affirmations?: unknown;
75	}
76	
77	function jsonResponse(status: number, body: unknown): Response {
78	  return new Response(JSON.stringify(body), {
79	    status,
80	    headers: { ...corsHeaders, "Content-Type": "application/json" },
81	  });
82	}
83	
84	function bearerToken(req: Request): string | null {
85	  const raw = req.headers.get("Authorization") ??
86	    req.headers.get("authorization");
87	  if (!raw) return null;
88	  const m = raw.match(/^Bearer\s+(.+)$/i);
89	  return m ? m[1].trim() : null;
90	}
91	
92	function parseAffirmations(
93	  raw: unknown,
94	): Record<string, boolean> | null {
95	  if (raw === null || typeof raw !== "object" || Array.isArray(raw)) {
96	    return null;
97	  }
98	  const out: Record<string, boolean> = {};
99	  for (const [key, value] of Object.entries(raw as Record<string, unknown>)) {
100	    if (typeof value !== "boolean") return null;
101	    out[key] = value;
102	  }
103	  return out;
104	}
105	
106	Deno.serve(async (req) => {
107	  if (req.method === "OPTIONS") {
108	    return new Response(null, { status: 204, headers: corsHeaders });
109	  }
110	  if (req.method !== "POST") {
111	    return jsonResponse(405, { error: "METHOD_NOT_ALLOWED" });
112	  }
113	
114	  const token = bearerToken(req);
115	  if (!token) return jsonResponse(401, { error: "UNAUTHORIZED" });
116	
117	  let claims;
118	  try {
119	    claims = await verifyJwt(token);
120	  } catch {
121	    return jsonResponse(401, { error: "UNAUTHORIZED" });
122	  }
123	  if (claims.role !== "creator") {
124	    return jsonResponse(403, { error: "FORBIDDEN" });
125	  }
126	
127	  let body: SubmitVideoRequest;
128	  try {
129	    body = await req.json();
130	  } catch {
131	    return jsonResponse(400, { error: "INVALID_JSON" });
132	  }
133	
134	  const applicationId =
135	    typeof body.application_id === "string" && UUID_RE.test(body.application_id)
136	      ? body.application_id
137	      : null;
138	  if (!applicationId) {
139	    return jsonResponse(400, { error: "INVALID_REQUEST" });
140	  }
141	
142	  if (
143	    typeof body.video_url !== "string" ||
144	    body.video_url.trim().length === 0 ||
145	    body.video_url.length > VIDEO_URL_MAX_LEN
146	  ) {
147	    return jsonResponse(400, { error: "INVALID_REQUEST" });
148	  }
149	  const videoUrl = body.video_url.trim();
150	
151	  const affirmations = parseAffirmations(body.post_condition_affirmations);
152	  if (affirmations === null) {
153	    return jsonResponse(400, { error: "INVALID_REQUEST" });
154	  }
155	
156	  const classification = classifyVideoUrl(videoUrl);
157	  if (!classification) {
158	    return jsonResponse(422, { error: "INVALID_VIDEO_URL" });
159	  }
160	
161	  const supabaseUrl = Deno.env.get("SUPABASE_URL");
162	  const serviceRoleKey = Deno.env.get("SUPABASE_SERVICE_ROLE_KEY");
163	  if (!supabaseUrl || !serviceRoleKey) {
164	    return jsonResponse(500, { error: "SERVER_MISCONFIGURED" });
165	  }
166	
167	  const supabase = createClient(supabaseUrl, serviceRoleKey, {
168	    auth: { persistSession: false, autoRefreshToken: false },
169	  });
170	
171	  const { data: application, error: appError } = await supabase
172	    .from("applications")
173	    .select("id,creator_id,status,listing_version_id")
174	    .eq("id", applicationId)
175	    .maybeSingle();
176	
177	  if (appError) {
178	    console.error("applications lookup failed", appError);
179	    return jsonResponse(500, { error: "DB_ERROR" });
180	  }
181	  if (!application || application.creator_id !== claims.sub) {
182	    return jsonResponse(404, { error: "APPLICATION_NOT_FOUND" });
183	  }
184	  if (application.status !== "approved") {
185	    return jsonResponse(403, { error: "APPLICATION_NOT_APPROVED" });
186	  }
187	
188	  const { data: postConditions, error: condError } = await supabase
189	    .from("listing_conditions")
190	    .select("id")
191	    .eq("listing_version_id", application.listing_version_id)
192	    .eq("kind", "post");
193	
194	  if (condError) {
195	    console.error("listing_conditions lookup failed", condError);
196	    return jsonResponse(500, { error: "DB_ERROR" });
197	  }
198	
199	  const missing: string[] = [];
200	  for (const row of postConditions ?? []) {
201	    if (affirmations[row.id] !== true) missing.push(row.id);
202	  }
203	  if (missing.length > 0) {
204	    return jsonResponse(422, {
205	      error: "INCOMPLETE_AFFIRMATIONS",
206	      missing_condition_ids: missing,
207	    });
208	  }
209	
210	  // oEmbed lives after the cheap checks — a TikTok network call on a
211	  // request that would 404/403/422 anyway is pure waste and exposes
212	  // rate-limit surface to unauthenticated noise.
213	  let oembed: OembedResult | null = null;
214	  if (classification.platform === "tiktok") {
215	    try {
216	      oembed = await fetchTikTokOembed(videoUrl);
217	    } catch (err) {
218	      console.error("TikTok oEmbed fetch error", err);
219	      return jsonResponse(500, { error: "DB_ERROR" });
220	    }
221	    if (!oembed) {
222	      return jsonResponse(422, { error: "INVALID_VIDEO_URL" });
223	    }
224	  }
225	
226	  const { data: rpcData, error: rpcError } = await supabase.rpc(
227	    "submit_video_rpc",
228	    {
229	      p_application_id: applicationId,
230	      p_creator_id: claims.sub,
231	      p_video_url: videoUrl,
232	      p_platform: classification.platform,
233	      p_external_id: classification.externalId,
234	      p_oembed: oembed ? oembed.raw : null,
235	    },
236	  );
237	
238	  if (rpcError) {
239	    console.error("submit_video_rpc error", rpcError);
240	    return jsonResponse(500, { error: "DB_ERROR" });
241	  }
242	
243	  const result = rpcData as
244	    | { submission_id?: string; error?: string }
245	    | null;
246	
247	  if (result?.error === "APPLICATION_NOT_FOUND") {
248	    return jsonResponse(404, { error: "APPLICATION_NOT_FOUND" });
249	  }
250	  if (result?.error === "APPLICATION_NOT_APPROVED") {
251	    return jsonResponse(403, { error: "APPLICATION_NOT_APPROVED" });
252	  }
253	  if (result?.error === "SUBMISSION_EXISTS") {
254	    return jsonResponse(409, { error: "SUBMISSION_EXISTS" });
255	  }
256	
257	  if (!result?.submission_id) {
258	    console.error("submit_video_rpc returned unexpected shape", result);
259	    return jsonResponse(500, { error: "DB_ERROR" });
260	  }
261	
262	  return jsonResponse(200, {
263	    submission_id: result.submission_id,
264	    platform: classification.platform,
265	  });
266	});
