69	function b64url(bytes: Uint8Array): string {
70	  let s = "";
71	  for (const b of bytes) s += String.fromCharCode(b);
72	  return btoa(s).replaceAll("+", "-").replaceAll("/", "_").replace(/=+$/, "");
