75	async function signMarketifyJwt(
76	  claims: { sub: string; role: "creator" | "lister"; session_id: string },
77	  secret: string,
78	): Promise<string> {
79	  const now = Math.floor(Date.now() / 1000);
80	  const payload = { ...claims, iat: now, exp: now + 300 };
81	  const header = b64url(
82	    encoder.encode(JSON.stringify({ alg: "HS256", typ: "JWT" })),
83	  );
84	  const body = b64url(encoder.encode(JSON.stringify(payload)));
85	  const signingInput = `${header}.${body}`;
86	  const key = await crypto.subtle.importKey(
87	    "raw",
88	    encoder.encode(secret),
89	    { name: "HMAC", hash: "SHA-256" },
90	    false,
91	    ["sign"],
92	  );
93	  const sig = await crypto.subtle.sign(
94	    "HMAC",
95	    key,
96	    encoder.encode(signingInput),
97	  );
98	  return `${signingInput}.${b64url(new Uint8Array(sig))}`;
99	}
